import { describe, it, expect } from 'vitest';
import { formatDate } from '../../src/components/NoteItem';

describe('formatDate', () => {
  it('should handle happy path with a valid ISO string', () => {
    const isoString = '2024-05-25T14:30:00Z';
    const result = formatDate(isoString);
    expect(typeof result).toBe('string');
    // expect a basic date format, e.g., "May 25, 2024" or "2024-05-25"
    // The exact format is not specified, just ensure it contains the date part.
    expect(result).toMatch(/[A-Za-z]{3,}\s\d{1,2},\s\d{4}/i).toBeTruthy()
      .or
      .expect(result).toMatch(/\d{4}-\d{2}-\d{2}/);
  });

  it('should handle edge case with an ISO string containing timezone offset', () => {
    const isoString = '2024-12-31T23:59:60+02:00'; // Leap second and offset
    const result = formatDate(isoString);
    expect(typeof result).toBe('string');
    // Ensure the formatted date still reflects the year, month and day
    expect(result).toMatch(/\d{4}-\d{2}-\d{2}/);
  });

  it('should handle null/empty input gracefully', () => {
    const resultA = formatDate(null as any);
    const resultU = formatDate(undefined as any);
    const resultE = formatDate('');
    expect(resultA).toBeDefined();
    expect(resultU).toBeDefined();
    expect(resultE).toBeDefined();
    // Expect the output to be an empty string or a safe default string
    expect(resultA).toMatch(/^\s*$/);
    expect(resultU).toMatch(/^\s*$/);
    expect(resultE).toMatch(/^\s*$/);
  });
});

// ── Tests for truncateContent  ──

import { describe, it, expect } from 'vitest';
import { truncateContent } from '../../src/components/NoteItem';

describe('truncateContent', () => {
  it('should handle happy path by truncating content longer than maxLength', () => {
    const content = 'This is a very long note content that definitely exceeds the default maximum length of eighty characters';
    const result = truncateContent(content, 80);
    expect(result).toBe('This is a very long note content that definitely exceeds the default maximum length of ei...');
    expect(result.length).toBe(80);
  });

  it('should handle edge case when content is exactly at maxLength boundary', () => {
    const content = '12345678901234567890123456789012345678901234567890123456789012345678901234567890';
    const result = truncateContent(content, 80);
    expect(result).toBe(content);
    expect(result.length).toBe(80);
  });

  it('should handle null/empty content values', () => {
    expect(truncateContent('', 80)).toBe('');
    expect(truncateContent(null as unknown as string, 80)).toBe('');
    expect(truncateContent(undefined as unknown as string, 80)).toBe('');
    expect(truncateContent('', 0)).toBe('');
  });
});

